// 上壇之律：唯「已核」得渲染；餘者退種字／三昧耶形（寧缺毋誤）
export function 已核之(id, side) {
    const g = 依號[id];
    const f = g && g[side];
    return f && f.信 === '已核' ? f : null;
}
// 舊名之通（mandala 相容）
export { 儀軌 as GIKI, 依號 as gikiById, 已核之 as kosareta };
